css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; display: flex; justify-content: center; padding: 40px 20px; min-height: 100vh; }
.app { width: 100%; max-width: 420px; }
h1 { font-size: 26px; font-weight: 800; text-align: center; margin-bottom: 8px; }
.subtitle { text-align: center; color: rgba(255,255,255,0.4); font-size: 13.5px; margin-bottom: 28px; }
.preview { height: 140px; border-radius: 20px; background: #6366f1; display: flex; align-items: center; justify-content: center; margin-bottom: 24px; transition: background 0.1s; }
.hex-display { font-size: 22px; font-weight: 800; color: white; background: rgba(0,0,0,0.2); padding: 8px 20px; border-radius: 999px; letter-spacing: 0.05em; }
.sliders { display: flex; flex-direction: column; gap: 14px; margin-bottom: 24px; }
.slider-row { display: flex; align-items: center; gap: 12px; }
.slider-row label { width: 16px; font-weight: 800; font-size: 14px; color: rgba(255,255,255,0.5); }
.slider-row input { flex: 1; }
.slider-row span { width: 36px; text-align: right; font-size: 13px; font-weight: 700; color: rgba(255,255,255,0.6); }
#r { accent-color: #f87171; }
#g { accent-color: #4ade80; }
#b { accent-color: #60a5fa; }
.formats { display: flex; flex-direction: column; gap: 8px; margin-bottom: 28px; }
.format-row { display: flex; align-items: center; gap: 12px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 12px; padding: 12px 16px; cursor: pointer; }
.format-row:hover { background: rgba(255,255,255,0.06); }
.format-label { font-size: 12px; font-weight: 800; color: rgba(255,255,255,0.4); width: 36px; }
.format-value { flex: 1; font-size: 14px; font-weight: 600; font-family: monospace; }
.copy-icon { font-size: 14px; }
h2 { font-size: 16px; font-weight: 700; margin-bottom: 14px; }
.palette-grid { display: grid; grid-template-columns: repeat(5, 1fr); gap: 8px; margin-bottom: 28px; }
.palette-color { aspect-ratio: 1; border-radius: 10px; cursor: pointer; transition: 0.15s; border: 2px solid transparent; }
.palette-color:hover { transform: scale(1.08); border-color: rgba(255,255,255,0.3); }
.complementary { display: flex; gap: 8px; }
.comp-color { flex: 1; aspect-ratio: 1; border-radius: 10px; cursor: pointer; display: flex; align-items: flex-end; justify-content: center; padding-bottom: 6px; transition: 0.15s; }
.comp-color:hover { transform: scale(1.05); }
.comp-color span { font-size: 10px; font-weight: 700; background: rgba(0,0,0,0.3); padding: 2px 6px; border-radius: 6px; color: white; }

