const palettes = [
  '#6366f1','#ec4899','#f97316','#22c55e','#38bdf8',
  '#a855f7','#facc15','#ef4444','#14b8a6','#f472b6'
];

function rgbToHex(r, g, b) {
  return '#' + [r, g, b].map(x => x.toString(16).padStart(2, '0')).join('').toUpperCase();
}

function rgbToHsl(r, g, b) {
  r /= 255; g /= 255; b /= 255;
  const max = Math.max(r, g, b), min = Math.min(r, g, b);
  let h, s, l = (max + min) / 2;
  if (max === min) { h = s = 0; }
  else {
    const d = max - min;
    s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
    switch (max) {
      case r: h = (g - b) / d + (g < b ? 6 : 0); break;
      case g: h = (b - r) / d + 2; break;
      case b: h = (r - g) / d + 4; break;
    }
    h /= 6;
  }
  return [Math.round(h * 360), Math.round(s * 100), Math.round(l * 100)];
}

function updateFromSliders() {
  const r = parseInt(document.getElementById('r').value);
  const g = parseInt(document.getElementById('g').value);
  const b = parseInt(document.getElementById('b').value);

  document.getElementById('rVal').textContent = r;
  document.getElementById('gVal').textContent = g;
  document.getElementById('bVal').textContent = b;

  const hex = rgbToHex(r, g, b);
  const [h, s, l] = rgbToHsl(r, g, b);

  document.getElementById('preview').style.background = hex;
  document.getElementById('hexDisplay').textContent = hex;
  document.getElementById('hexFormat').textContent = hex;
  document.getElementById('rgbFormat').textContent = `rgb(${r}, ${g}, ${b})`;
  document.getElementById('hslFormat').textContent = `hsl(${h}, ${s}%, ${l}%)`;

  renderComplementary(h, s, l);
}

function copyValue(type) {
  const value = document.getElementById(type + 'Format').textContent;
  navigator.clipboard?.writeText(value).catch(() => {});
  alert(`${value} kopyalandı!`);
}

function setColorFromHex(hex) {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  document.getElementById('r').value = r;
  document.getElementById('g').value = g;
  document.getElementById('b').value = b;
  updateFromSliders();
}

function renderComplementary(h, s, l) {
  const container = document.getElementById('complementary');
  container.innerHTML = '';
  const offsets = [0, 30, 60, 180, 210];
  offsets.forEach(offset => {
    const newH = (h + offset) % 360;
    const div = document.createElement('div');
    div.className = 'comp-color';
    div.style.background = `hsl(${newH}, ${s}%, ${l}%)`;
    div.innerHTML = `<span>+${offset}°</span>`;
    div.addEventListener('click', () => {
      navigator.clipboard?.writeText(`hsl(${newH}, ${s}%, ${l}%)`).catch(() => {});
      alert(`hsl(${newH}, ${s}%, ${l}%) kopyalandı!`);
    });
    container.appendChild(div);
  });
}

function renderPalettes() {
  const grid = document.getElementById('paletteGrid');
  palettes.forEach(color => {
    const div = document.createElement('div');
    div.className = 'palette-color';
    div.style.background = color;
    div.addEventListener('click', () => setColorFromHex(color));
    grid.appendChild(div);
  });
}

renderPalettes();
updateFromSliders();
